let config=await getConfig(),userCourseConfig=getUserCourseConfig();async function getConfig(){try{let e=document.getElementById("prefetch-config-link-element"),t=await fetch(e.getAttribute("href"));return await t.json()}catch(n){return}}function getUserCourseConfig(){if(!config)return;let e=getUserCourse(),t=config.courses.find(t=>t.name===e),n=config.courses.find(e=>"fallback"===e.name);return t||n}function getUserCourse(){let e=localStorage.getItem("gaUserCourse");if(window.location.pathname.includes("canvas-landing-pages")){let t=window.location.pathname.split("/").pop();return localStorage.setItem("gaUserCourse",t),t}return e?e:"fallback"}export{config,userCourseConfig};